#!/usr/bin/env node
import { mkdirSync, writeFileSync } from 'node:fs';
import { dirname } from 'node:path';
import { resolve } from 'node:path';

import { AGENTS, AGENT_FLAGS, AGENT_BY_FLAG } from './agents.mjs';
import { detectTechnologies, collectSkills, getInstalledSkillNames, detectInstalledAgents } from './detect.mjs';
import { fetchSkillContents } from './mcp-client.mjs';
import {
  printIntro,
  printOutro,
  printDetected,
  printDryRun,
  promptAgents,
  promptSkills,
  runWithProgress,
} from './ui.mjs';

// ── Arg Parsing ──────────────────────────────────────────────

function parseArgs(argv) {
  const args = argv.slice(2);
  const flags = {
    agents: [],
    dryRun: false,
    yes: false,
    dir: process.cwd(),
    help: false,
  };

  for (let i = 0; i < args.length; i++) {
    const arg = args[i];
    if (arg === '--dry-run' || arg === '-d') {
      flags.dryRun = true;
    } else if (arg === '-y' || arg === '--yes') {
      flags.yes = true;
    } else if (arg === '--help' || arg === '-h') {
      flags.help = true;
    } else if (arg === '--dir' && args[i + 1]) {
      flags.dir = resolve(args[++i]);
    } else if (arg.startsWith('--')) {
      const flag = arg.slice(2);
      if (AGENT_FLAGS.includes(flag)) {
        flags.agents.push(flag);
      } else {
        console.error(`Unknown flag: ${arg}`);
        process.exit(1);
      }
    }
  }

  return flags;
}

function printHelp() {
  console.log(`
  agentskills — detect your stack and install AI agent skills via MCP

  Usage:
    npx agentskills [options]

  Agent flags (select target agents):
${Object.values(AGENTS)
  .map((a) => `    --${a.flag.padEnd(16)} ${a.name}`)
  .join('\n')}

  Options:
    --dry-run, -d    Preview skills without installing
    -y, --yes        Skip confirmations (install all suggested)
    --dir <path>     Project directory to scan (default: cwd)
    --help, -h       Show this help

  Examples:
    npx agentskills
    npx agentskills --claude-code
    npx agentskills --claude-code --dry-run
    npx agentskills --claude-code -y
`);
}

// ── Installer ────────────────────────────────────────────────

/**
 * Installs a single skill for each selected agent.
 * Fetches content from GitHub and writes to each agent's installDir.
 * Returns { success, paths } or { success: false, error }.
 */
async function installSkill(skill, agentFlags, targetDir) {
  const paths = [];

  for (const flag of agentFlags) {
    const agent = AGENT_BY_FLAG[flag];
    if (!agent) continue;

    const files = await fetchSkillContents(
      [skill],
      targetDir,
      agent.installDir,
      agent.fileTemplate,
    );

    for (const { path, content } of files) {
      const dir = dirname(path);
      mkdirSync(dir, { recursive: true });
      writeFileSync(path, content, 'utf-8');
      paths.push(path);
    }
  }

  if (!paths.length) {
    return { success: false, error: 'No files written' };
  }

  return { success: true, paths };
}

// ── Main ─────────────────────────────────────────────────────

async function main() {
  const flags = parseArgs(process.argv);

  if (flags.help) {
    printHelp();
    process.exit(0);
  }

  printIntro();

  const projectDir = flags.dir;

  // 1. Detect stack
  const { detected, isFrontend } = detectTechnologies(projectDir);
  printDetected(detected, [], isFrontend);

  // 2. Collect skill suggestions (based on detected stack)
  const installedNames = getInstalledSkillNames(projectDir);
  const suggestions = collectSkills({ detected, installedNames });

  // 3. Resolve target agents
  let agentFlags = flags.agents;
  if (!agentFlags.length) {
    const installedAgents = detectInstalledAgents();
    agentFlags = await promptAgents(installedAgents, Object.values(AGENTS));
  }

  // 4. Prompt skill selection (unless -y)
  let selected; // [{ skillName, version }]

  if (flags.yes) {
    selected = suggestions
      .filter((s) => !s.alreadyInstalled)
      .map(({ skillName, repo, subdir }) => ({ skillName, repo, subdir }));
  } else {
    const enriched = suggestions.map((s) => ({
      ...s,
      displayName: s.skillName,
      description: s.repo ? `github.com/${s.repo}` : '',
    }));

    const pickedPaths = await promptSkills(enriched);
    selected = pickedPaths.map((key) => {
      const skillName = key.split('@')[0];
      const match = suggestions.find((s) => s.skillName === skillName);
      return { skillName, repo: match?.repo, subdir: match?.subdir };
    });
  }

  if (!selected.length) {
    printOutro(0, 0);
    process.exit(0);
  }

  // 5. Dry-run or install
  if (flags.dryRun) {
    printDryRun(
      selected.map((s) => s.skillName),
      agentFlags,
    );
    printOutro(0, 0);
    process.exit(0);
  }

  // 6. Install
  const { installed, failed } = await runWithProgress(
    selected,
    agentFlags,
    async (skill) => {
      try {
        const result = await installSkill(skill, agentFlags, projectDir);
        return { success: result.success, output: result.error || '' };
      } catch (err) {
        return { success: false, output: err.message };
      }
    },
  );

  printOutro(installed, failed);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
